const outcomes = $node['Fetch Agent Outcomes (Last 7 Days)'].json.outcomes || [];
const metrics = $node['Fetch Performance Metrics (Last 7 Days)'].json.metrics || [];
const by_agent = {};
outcomes.forEach(o => {
  if (!by_agent[o.agent_slug]) {
    by_agent[o.agent_slug] = {
      total_tasks: 0,
      successful_tasks: 0,
      failed_tasks: 0,
      total_tokens: 0,
      total_latency_ms: 0,
      failures: []
    };
  }
  by_agent[o.agent_slug].total_tasks += 1;
  if (o.success) {
    by_agent[o.agent_slug].successful_tasks += 1;
  } else {
    by_agent[o.agent_slug].failed_tasks += 1;
    by_agent[o.agent_slug].failures.push(o.error || 'unknown');
  }
  by_agent[o.agent_slug].total_tokens += o.tokens_used || 0;
  by_agent[o.agent_slug].total_latency_ms += o.latency_ms || 0;
});
const agent_stats = Object.entries(by_agent).map(([agent_slug, data]) => ({
  agent_slug,
  success_rate: (data.successful_tasks / data.total_tasks * 100).toFixed(2) + '%',
  task_count: data.total_tasks,
  avg_tokens_per_task: (data.total_tokens / data.total_tasks).toFixed(0),
  avg_latency_ms: (data.total_latency_ms / data.total_tasks).toFixed(0),
  failure_rate: (data.failed_tasks / data.total_tasks * 100).toFixed(2) + '%',
  top_errors: data.failures.slice(0, 3)
}));
const top_agents = agent_stats.sort((a, b) => parseFloat(b.success_rate) - parseFloat(a.success_rate)).slice(0, 5);
const struggling_agents = agent_stats.sort((a, b) => parseFloat(a.success_rate) - parseFloat(b.success_rate)).slice(0, 3);
return [{
  json: {
    analysis_week: new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0],
    total_tasks: outcomes.length,
    total_unique_agents: Object.keys(by_agent).length,
    overall_success_rate: (outcomes.filter(o => o.success).length / outcomes.length * 100).toFixed(2) + '%',
    all_agents_stats: agent_stats,
    top_performing_agents: top_agents,
    struggling_agents: struggling_agents,
    total_tokens_week: outcomes.reduce((s, o) => s + (o.tokens_used || 0), 0),
    analysis_timestamp: new Date().toISOString()
  }
}];

