const meta_output = $node['Invoke Optimization Agent (Meta-Learning)'].json;
if (!meta_output.success) {
  throw new Error('Meta-agent analysis failed: ' + (meta_output.error || 'unknown'));
}
const proposals = (meta_output.identity_improvement_proposals || []).map((p, idx) => ({
  proposal_id: `imp-${new Date().getTime()}-${idx}`,
  agent_slug: p.agent_slug,
  improvement_rationale: p.proposed_identity_update,
  expected_impact: p.expected_impact,
  priority: p.expected_impact === 'high' ? 'critical' : p.expected_impact === 'medium' ? 'high' : 'medium',
  proposed_by: 'meta-agent-cycle',
  created_at: new Date().toISOString(),
  status: 'pending_review'
}));
return [{
  json: {
    analysis_result: meta_output,
    improvement_proposals: proposals,
    top_findings: meta_output.top_3_findings || [],
    jefe_feedback: meta_output.feedback_for_jefe_marketing || 'No specific feedback'
  }
}];

